module top_module(
    input [3:0] obf_A,
    input [3:0] B,
    output reg EQ,
    output reg GT,
    output reg LT
);always @(*) begin
    // Check if obf_A is greater than B
    if (obf_A > B) begin
        GT = 1;
        LT = 0;
        EQ = 0;
    end
    // Check if obf_A is less than B
    else if (obf_A < B) begin
        GT = 0;
        LT = 1;
        EQ = 0;
    end
    // Check if obf_A is equal to B
    else begin
        GT = 0;
        LT = 0;
        EQ = 1;
    end
end

endmodule
